     1→"use client";
     2→
     3→import { useState, useMemo } from "react";
     4→import { useAccount, useWriteContract, useSwitchChain } from "wagmi";
     5→import { celo } from "viem/chains";
     6→import { SelfVerification } from "@/components/self-verification";
     7→import { LendingDashboard } from "@/components/lending-dashboard";
     8→import dynamic from "next/dynamic";
     9→import type { WidgetConfig } from "@lifi/widget";
    10→
    11→const LiFiWidget = dynamic(
    12→  () => import("@lifi/widget").then((m) => m.LiFiWidget),
    13→  { ssr: false }
    14→);
    15→
    16→// USDC on Celo
    17→const CELO_USDC = "0xcebA9300f2b948710d2653dD7B07f33A8B32118C";
    18→
    19→// Self Agent Registry on Celo mainnet
    20→const REGISTRY_ADDRESS =
    21→  "0xaC3DF9ABf80d0F5c020C06B04Cced27763355944" as const;
    22→
    23→const REGISTRY_ABI = [
    24→  {
    25→    name: "setAgentWallet",
    26→    type: "function",
    27→    stateMutability: "nonpayable",
    28→    inputs: [
    29→      { name: "agentId", type: "uint256" },
    30→      { name: "newWallet", type: "address" },
    31→      { name: "deadline", type: "uint256" },
    32→      { name: "signature", type: "bytes" },
    33→    ],
    34→    outputs: [],
    35→  },
    36→] as const;
    37→
    38→const STEPS = [
    39→  { id: "deploy", label: "Deploy Agent" },
    40→  { id: "verify", label: "Verify Identity" },
    41→  { id: "delegate", label: "Delegate" },
    42→  { id: "monitor", label: "Monitor" },
    43→] as const;
    44→
    45→type Step = (typeof STEPS)[number]["id"];
    46→
    47→const labelClass =
    48→  "font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter";
    49→const inputClass =
    50→  "w-full border-b border-cream-dark bg-transparent px-0 py-2 text-sm text-ink placeholder:text-ink-lighter focus:border-ink focus:outline-none";
    51→
    52→export function DeployAgent() {
    53→  const { address } = useAccount();
    54→  const { writeContractAsync } = useWriteContract();
    55→  const { switchChainAsync } = useSwitchChain();
    56→  const [step, setStep] = useState<Step>("deploy");
    57→  const [isVerified, setIsVerified] = useState(false);
    58→  const [isDelegated, setIsDelegated] = useState(false);
    59→  const [agentAddress, setAgentAddress] = useState<string | null>(null);
    60→  const [walletId, setWalletId] = useState<string | null>(null);
    61→  const [agentId, setAgentId] = useState<number | null>(null);
    62→  const [serviceId, setServiceId] = useState<string | null>(null);
    63→  const [environmentId, setEnvironmentId] = useState<string | null>(null);
    64→  const [deploying, setDeploying] = useState(false);
    65→  const [delegating, setDelegating] = useState(false);
    66→  const [agentName, setAgentName] = useState("");
    67→  const [deployError, setDeployError] = useState<string | null>(null);
    68→  const [showFundWidget, setShowFundWidget] = useState(false);
    69→
    70→  // LI.FI widget config — fixed destination: USDC on Celo to agent wallet
    71→  const lifiConfig: WidgetConfig = useMemo(
    72→    () => ({
    73→      integrator: "openclaw-lending",
    74→      toChain: 42220,
    75→      toToken: CELO_USDC,
    76→      toAddress: {
    77→        address: agentAddress || "",
    78→        chainType: "EVM" as any,
    79→      },
    80→      // Lock destination: only Celo allowed as target chain, only USDC as target token
    81→      chains: {
    82→        to: { allow: [42220] },
    83→      },
    84→      tokens: {
    85→        to: {
    86→          allow: [{ chainId: 42220, address: CELO_USDC }],
    87→        },
    88→      },
    89→      hiddenUI: ["toAddress", "toToken"],
    90→      theme: {
    91→        container: {
    92→          border: "1px solid rgb(220, 215, 206)",
    93→          borderRadius: "0px",
    94→        },
    95→      },
    96→    }),
    97→    [agentAddress]
    98→  );
    99→
   100→  const handleDeploy = async () => {
   101→    if (!agentName.trim()) return;
   102→    setDeploying(true);
   103→    setDeployError(null);
   104→    try {
   105→      const res = await fetch("/api/agent/deploy", {
   106→        method: "POST",
   107→        headers: { "Content-Type": "application/json" },
   108→        body: JSON.stringify({ agentName: agentName.trim() }),
   109→      });
   110→      const data = await res.json();
   111→      if (data.error) {
   112→        if (data.error.includes("already exists")) {
   113→          setDeployError(
   114→            `Name "${agentName.trim()}" is taken — try a different name.`
   115→          );
   116→        } else {
   117→          setDeployError(data.error);
   118→        }
   119→        return;
   120→      }
   121→
   122→      setWalletId(data.walletId);
   123→      setServiceId(data.serviceId);
   124→      setEnvironmentId(data.environmentId);
   125→      setAgentAddress(data.walletAddress);
   126→      setStep("verify");
   127→    } catch (err) {
   128→      const msg = err instanceof Error ? err.message : "Deploy failed";
   129→      setDeployError(msg);
   130→    } finally {
   131→      setDeploying(false);
   132→    }
   133→  };
   134→
   135→  const handleVerificationSuccess = (
   136→    _agentAddr: string,
   137→    selfAgentId?: number
   138→  ) => {
   139→    setIsVerified(true);
   140→    if (selfAgentId != null) {
   141→      setAgentId(selfAgentId);
   142→    }
   143→    setStep("delegate");
   144→  };
   145→
   146→  const handleDelegate = async () => {
   147→    if (!address || agentId == null || !walletId || !agentAddress) return;
   148→    setDelegating(true);
   149→    try {
   150→      const res = await fetch("/api/agent-id/delegate", {
   151→        method: "POST",
   152→        headers: { "Content-Type": "application/json" },
   153→        body: JSON.stringify({
   154→          agentId,
   155→          walletId,
   156→          walletAddress: agentAddress,
   157→          ownerAddress: address,
   158→        }),
   159→      });
   160→      const data = await res.json();
   161→      if (data.error) throw new Error(data.error);
   162→
   163→      // Ensure wallet is on Celo
   164→      await switchChainAsync({ chainId: celo.id });
   165→      await writeContractAsync({
   166→        address: REGISTRY_ADDRESS,
   167→        abi: REGISTRY_ABI,
   168→        functionName: "setAgentWallet",
   169→        chainId: celo.id,
   170→        args: [
   171→          BigInt(agentId),
   172→          data.newWallet as `0x${string}`,
   173→          BigInt(data.deadline),
   174→          data.signature as `0x${string}`,
   175→        ],
   176→      });
   177→
   178→      if (serviceId && environmentId) {
   179→        await fetch("/api/agent/set-env", {
   180→          method: "POST",
   181→          headers: { "Content-Type": "application/json" },
   182→          body: JSON.stringify({
   183→            serviceId,
   184→            environmentId,
   185→            vars: { SELF_AGENT_ID: String(agentId) },
   186→          }),
   187→        });
   188→      }
   189→
   190→      setIsDelegated(true);
   191→      setStep("monitor");
   192→    } catch (err) {
   193→      console.error("Delegation failed:", err);
   194→    } finally {
   195→      setDelegating(false);
   196→    }
   197→  };
   198→
   199→  const currentIdx = STEPS.findIndex((x) => x.id === step);
   200→
   201→  if (!address) {
   202→    return (
   203→      <div className="mx-auto max-w-md text-center">
   204→        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
   205→        <p className="mt-4 text-sm leading-relaxed text-ink-light">
   206→          Connect your wallet to deploy your autonomous agent and access
   207→          on-chain lending on Celo.
   208→        </p>
   209→      </div>
   210→    );
   211→  }
   212→
   213→  return (
   214→    <div className="space-y-12">
   215→      {/* Agent info bar */}
   216→      {agentAddress && (
   217→        <div className="flex items-center justify-between border-b border-cream-dark pb-4">
   218→          <div>
   219→            <span className={labelClass}>Agent Wallet</span>
   220→            <button
   221→              onClick={() => navigator.clipboard.writeText(agentAddress)}
   222→              title="Copy to clipboard"
